import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o,c,e as d}from"./app-02133217.js";const a="/408CSFamily/assets/队列的基本结构-51459c13.png",i={},t=d('<h1 id="队列的基本概念和操作" tabindex="-1"><a class="header-anchor" href="#队列的基本概念和操作" aria-hidden="true">#</a> 队列的基本概念和操作</h1><h2 id="基本概念" tabindex="-1"><a class="header-anchor" href="#基本概念" aria-hidden="true">#</a> 基本概念</h2><p><code>队列</code>：和栈一样，是一种操作受限制的线性表,只允许在表的一端进行插入，在表的另外一端进行删除，简称为<code>队</code>，常记作：<code>Queue</code></p><p><code>入队</code>： 向队列中插入元素，也叫做<code>进队</code></p><p><code>出队</code>： 删除队列元素，也叫做<code>离队</code></p><figure><img src="'+a+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>结合生活中排队的经验，在群体素质高、无人插队的情况下(<code>薛定谔排队</code>,噗呲，哈哈哈),<strong>一般最早排队的也是最早离队的</strong>，和栈的<code>后进先出</code>不一样的是，队列是<code>先进先出</code>的，即：First In Frist Out</p><blockquote><p>Tips</p><ul><li>栈：又叫做后进先出的线性表</li><li>队列：又叫做先进先出的线性表</li></ul></blockquote><p><code>队头</code>：允许进行删除操作的一端，也叫做<code>队首</code>，常记作：<code>Front</code></p><p><code>队尾</code>：允许进行插入操作的一端，常记作：<code>Rear</code></p><p><code>空队列</code>：不含任何元素的空表，注意这个表是指<code>线性表</code></p><h2 id="基础操作" tabindex="-1"><a class="header-anchor" href="#基础操作" aria-hidden="true">#</a> 基础操作</h2><blockquote><p>和栈一样，队列是操作受限的线性表，具有<code>先进先出</code>的特性，不是任何对线性表的操作都可以作为队列的操作。例如：无法随便读取到队列中间的某个数据，需要将前面的元素先出队</p></blockquote><ul><li><code>InitQueue(&amp;Q)</code>： 初始化一个队列，构造空队列Q</li><li><code>QueueEmpty(Q)</code>： 判断队列是否为空，队空返回true,否则返回false</li><li><code>EnEmpty(&amp;Q,x)</code>： 入队，如果队列Q未满，将x入队，成为新的队尾元素</li><li><code>DeEmpty(&amp;Q,&amp;x)</code>： 出队，如果队列Q非空，删除队头元素，复制给x返回</li><li><code>GetHead(Q,&amp;x)</code>： 读取队头元素，如果队列Q非空，则将队头元素赋值给x</li></ul>',14),r=[t];function l(p,n){return o(),c("div",null,r)}const h=e(i,[["render",l],["__file","queue-basic-concepts.html.vue"]]);export{h as default};
